collections.template:
import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

public class CollectionsDemo {
    public static void main(String[] args) {
        // ArrayList (dynamic array)
        ArrayList<String> fruits = new ArrayList<>();
        fruits.add("Apple");
        fruits.add("Banana");
        System.out.println("ArrayList: " + fruits);

        // HashMap (key-value pairs)
        HashMap<String, Integer> cityPopulations = new HashMap<>();
        cityPopulations.put("New York", 8_400_000);
        cityPopulations.put("Tokyo", 14_000_000);
        System.out.println("Population of Tokyo: " + cityPopulations.get("Tokyo"));

        // Iterating over a map
        for (Map.Entry<String, Integer> entry : cityPopulations.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}

loops.template:
import java.util.ArrayList;

public class LoopsDemo {
    public static void main(String[] args) {
        // Standard for loop
        System.out.println("Standard for loop:");
        for (int i = 0; i < 5; i++) {
            System.out.print(i + " ");
        }
        System.out.println();

        // Enhanced for-each loop
        ArrayList<String> names = new ArrayList<>();
        names.add("Alice");
        names.add("Bob");
        System.out.println("\nFor-each loop:");
        for (String name : names) {
            System.out.print(name + " ");
        }
        System.out.println();

        // While loop
        int count = 5;
        System.out.println("\nWhile loop:");
        while (count > 0) {
            System.out.print(count + " ");
            count--;
        }
        System.out.println();
    }
}

