import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;

public class ExceptionDemo {
    public static void main(String[] args) {
        // The try-with-resources statement automatically closes the resource
        // when the block is exited, which is much safer than manual closing.
        try (BufferedReader reader = new BufferedReader(new FileReader("nonexistent.txt"))) {
            String line = reader.readLine();
            System.out.println(line);
        } catch (IOException e) {
            // This block catches the file-not-found error
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

basicThreading.template:
// A task that can be run on a new thread
class Worker implements Runnable {
    @Override
    public void run() {
        System.out.println("Worker thread starting...");
        try {
            Thread.sleep(1000); // Simulate some work
        } catch (InterruptedException e) {
            System.err.println("Worker thread interrupted.");
        }
        System.out.println("Worker thread finished.");
    }
}

public class ThreadingDemo {
    public static void main(String[] args) {
        System.out.println("Main thread starting...");

        Thread workerThread = new Thread(new Worker());
        workerThread.start(); // Start the new thread

        try {
            workerThread.join(); // Wait for the worker thread to finish
        } catch (InterruptedException e) {
            System.err.println("Main thread interrupted while waiting.");
        }

        System.out.println("Main thread finished.");
    }
}

generics.template:
// A generic class that can hold any type
class Box<T> {
    private T content;

    public void set(T content) {
        this.content = content;
    }

    public T get() {
        return content;
    }
}

public class GenericsDemo {
    // A generic method
    public static <E> void printArray(E[] inputArray) {
        for (E element : inputArray) {
            System.out.printf("%s ", element);
        }
        System.out.println();
    }

    public static void main(String[] args) {
        Box<Integer> integerBox = new Box<>();
        integerBox.set(10);
        System.out.println("Integer value: " + integerBox.get());

        Integer[] intArray = { 1, 2, 3 };
        String[] stringArray = { "Hello", "World" };
        printArray(intArray);
        printArray(stringArray);
    }
}

streamsApi.template:
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class StreamsDemo {
    public static void main(String[] args) {
        List<String> words = Arrays.asList("apple", "banana", "apricot", "cherry", "blueberry");

        // Use a stream to filter, transform, and collect results
        List<String> longWordsStartingWithA = words.stream()
                .filter(s -> s.startsWith("a")) // Keep words starting with 'a'
                .filter(s -> s.length() > 5)   // Keep words longer than 5 chars
                .map(String::toUpperCase)      // Convert to uppercase
                .sorted()                      // Sort alphabetically
                .collect(Collectors.toList()); // Collect results into a new list

        System.out.println(longWordsStartingWithA);
    }
}

