import java.util.ArrayList;
import java.util.Collections;

public class LambdaDemo {
    public static void main(String[] args) {
        // A simple lambda expression for a Runnable
        Runnable myRunnable = () -> System.out.println("Running in a lambda!");
        new Thread(myRunnable).start();

        // Using a lambda for sorting
        ArrayList<String> names = new ArrayList<>();
        names.add("Charlie");
        names.add("Alice");
        names.add("Bob");

        // Sort using a lambda expression for the comparator
        Collections.sort(names, (a, b) -> a.compareTo(b));
        System.out.println("Sorted names: " + names);
    }
}

enumsWithFields.template:
enum Planet {
    MERCURY (3.303e+23, 2.4397e6),
    VENUS   (4.869e+24, 6.0518e6),
    EARTH   (5.976e+24, 6.37814e6);

    private final double mass;   // in kilograms
    private final double radius; // in meters

    Planet(double mass, double radius) {
        this.mass = mass;
        this.radius = radius;
    }

    public double surfaceGravity() {
        final double G = 6.67300E-11;
        return G * mass / (radius * radius);
    }
}

public class EnumDemo {
    public static void main(String[] args) {
        Planet earth = Planet.EARTH;
        System.out.printf("Surface gravity on Earth is %.2f m/s^2\n", earth.surfaceGravity());
    }
}

abstractClasses.template:
abstract class Shape {
    // An abstract method must be implemented by subclasses
    public abstract double getArea();

    // A concrete method is inherited as-is
    public void printDescription() {
        System.out.println("This is a shape.");
    }
}

class Circle extends Shape {
    private double radius;

    public Circle(double radius) {
        this.radius = radius;
    }

    @Override
    public double getArea() {
        return Math.PI * radius * radius;
    }
}

public class AbstractDemo {
    public static void main(String[] args) {
        Shape myCircle = new Circle(5.0);
        myCircle.printDescription();
        System.out.printf("The area is %.2f\n", myCircle.getArea());
    }
}

