staticMembers.template:
class MathUtil {
    // A static field (constant) belongs to the class, not an instance
    public static final double PI = 3.14159;

    // A static method is called on the class itself
    public static int add(int a, int b) {
        return a + b;
    }
}

public class StaticDemo {
    public static void main(String[] args) {
        // Access static members using the class name
        System.out.println("Value of PI: " + MathUtil.PI);
        int sum = MathUtil.add(5, 10);
        System.out.println("5 + 10 = " + sum);
    }
}

dateTimeApi.template:
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class DateTimeDemo {
    public static void main(String[] args) {
        // Get the current date
        LocalDate today = LocalDate.now();
        System.out.println("Today's date: " + today);

        // Get the current date and time
        LocalDateTime now = LocalDateTime.now();
        System.out.println("Current date and time: " + now);

        // Formatting dates and times
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("MM/dd/yyyy HH:mm:ss");
        String formattedDateTime = now.format(formatter);
        System.out.println("Formatted: " + formattedDateTime);
    }
}
